				if ok {
					dispatch.Assigns[bestFeasibleIdx].GenRoute()
					if dispatch.Assigns[bestFeasibleIdx].Cost >= 0 {
						inserted = true
					} else {
						dispatch.Assigns[bestFeasibleIdx].RemoveShip(total_ship + i)
						dispatch.Assigns[bestFeasibleIdx].GenRoute()
					}
				}
			}
			if !inserted && assignsCap < MAXASSIGNS {
				newAi := assignsCap
